Randomization seed for the next random number, mask with 0x7FFF0000 for the last returned number.



int getRandomNumber(){

  lastRandomNumber = lastRandomNumber * 0x15A4E35 + 1;

  return (lastRandomNumber >> 16) & 0x7FFF;

}
